import clsx from 'clsx';
import { type ReactNode } from 'react';
import type { IntlShape } from 'react-intl';

import type { Precision } from '../../../core/time/shared.types.js';
import type { TimeframeSelectorState } from '../../../core/time/timeframeStore/timeframeSelector.types.js';
import { getTimeBoundaryMessageData } from '../../../core/time/validation.js';
import {
  extractDisplayValueFromTimeValues,
  getFromToValues,
  parseValue,
  messages,
} from '../../../forms/forms-core/time/timeParser.js';
import { Flex } from '../../../layouts/flex/Flex.js';
import { ellipsis as ellipsisCSS } from '../../../styles/ellipsis.sty.js';
import { Text } from '../../../typography/text/Text.js';
import { getTextFromNode } from '../../filter/utils/getTextFromNode.js';
import { TIMEFRAMESELECTOR_ERROR_MESSAGES } from '../constants/timeframeSelectorMessages.js';
import * as styles from '../TimeframeSelector.sty.js';

/**
 * Converts the given timeframe into a human-readable display value string.
 * @internal
 */
export function getTimeframeDisplayValueProps(
  value: TimeframeSelectorState['timeframeSelectorTimeframe'],
  intl: IntlShape,
  placeholder?: string,
  precision?: Precision,
  presetItemLabel?: ReactNode,
  required?: boolean,
  min?: string,
  max?: string,
) {
  if (!value) {
    return {
      displayValue: placeholder ?? '',
      isInvalid: !!required,
      hint: required ? intl.formatMessage(messages.requiredTimeframe) : '',
    };
  }

  if (presetItemLabel) {
    return {
      displayValue: getTextFromNode(presetItemLabel, intl, ''),
      isInvalid: false,
      hint: '',
    };
  }

  const { from, to } = parseValue(value);
  const { valueFrom, valueTo } = getFromToValues(value);

  const { displayValue, hint, isInvalid } = extractDisplayValueFromTimeValues(
    from,
    to,
    intl,
    precision,
    valueFrom,
    valueTo,
  );

  if (isInvalid) {
    return { displayValue, isInvalid, hint };
  }

  let hasError = false;
  let displayValueHint = '';

  const timeBoundaryMessageData = getTimeBoundaryMessageData(
    { from, to },
    min,
    max,
    precision,
  );

  if (timeBoundaryMessageData) {
    hasError = true;
    displayValueHint = intl.formatMessage(
      TIMEFRAMESELECTOR_ERROR_MESSAGES[timeBoundaryMessageData.errorKey],
      timeBoundaryMessageData.values,
    );
  }

  const displayValueParts = displayValue.split(' → ');

  const [displayValueFrom, displayValueTo] =
    displayValueParts.length === 2 ? displayValueParts : [];

  if (!displayValueFrom || !displayValueTo) {
    return { displayValue, isInvalid: hasError, hint: displayValueHint };
  }

  return {
    displayValue: (
      <Flex minWidth={0} gap={4}>
        <Text className={clsx(styles.displayValueParts, ellipsisCSS)}>
          {displayValueFrom}
        </Text>
        <Text style={{ minWidth: 'unset' }}>→</Text>
        <Text className={clsx(styles.displayValueParts, ellipsisCSS)}>
          {displayValueTo}
        </Text>
      </Flex>
    ),
    isInvalid: hasError,
    hint: displayValueHint,
  };
}
